pub(crate) fn build_folder_groups(site: &Site) -> Vec<FolderGroup> {
    let groups = site.folder_groups();
    let mut by_path: std::collections::BTreeMap<String, Vec<ArticleLink>> =
        std::collections::BTreeMap::new();
    for (path, articles) in groups {
        let links: Vec<ArticleLink> = articles
            .into_iter()
            .map(|a| ArticleLink {
                slug: a.slug.clone(),
                title: a.title.clone(),
            })
            .collect();
        by_path.entry(path).or_default().extend(links);
    }

    let root_articles = by_path.remove("").unwrap_or_default();
    let mut result = flatten_subtrees(&by_path, "", 0);

    if !root_articles.is_empty() {
        result.insert(
            0,
            FolderGroup {
                name: String::new(),
                slug: String::new(),
                depth: 0,
                articles: root_articles,
            },
        );
    }

    result
}

/// Collect distinct child folder names immediately under `prefix` and
/// emit one flat `FolderGroup` per child, then recurse at depth+1.
fn flatten_subtrees(
    by_path: &std::collections::BTreeMap<String, Vec<ArticleLink>>,
    prefix: &str,
    depth: usize,
) -> Vec<FolderGroup> {
    let mut result = Vec::new();

    // Folders directly under this prefix
    let prefix_slash = if prefix.is_empty() {
        String::new()
    } else {
        format!("{}/", prefix)
    };

    let child_names: Vec<String> = by_path
        .keys()
        .filter_map(|p| {
            if prefix_slash.is_empty() {
                // top-level: matches "xyz" (no slash)
                if !p.contains('/') {
                    Some(p.as_str())
                } else {
                    p.split_once('/').map(|(first, _)| first)
                }
            } else {
                p.strip_prefix(&prefix_slash)
                    .filter(|rest| !rest.is_empty())
                    .map(|rest| rest.split('/').next().unwrap())
            }
        })
        .map(|s| s.to_string())
        .collect::<BTreeSet<_>>()
        .into_iter()
        .collect();

    for name in child_names {
        let child_path = if prefix_slash.is_empty() {
            name.clone()
        } else {
            format!("{}{}", prefix_slash, name)
        };

        let direct = by_path.get(&child_path).cloned().unwrap_or_default();

        result.push(FolderGroup {
            name: name.clone(),
            slug: folder_to_slug(&child_path),
            depth: depth + 1,
            articles: direct,
        });

        result.extend(flatten_subtrees(by_path, &child_path, depth + 1));
    }

    result
}

/// Convert a folder name to a URL-safe slug.
pub fn folder_to_slug(name: &str) -> String {
    name.to_lowercase().replace(' ', "-")
}

/// Convert a URL-safe slug back to the original folder name.
pub fn slug_to_folder(slug: &str, site: &Site) -> Option<String> {
    for (folder_name, _) in site.folder_groups() {
        if folder_to_slug(&folder_name) == slug {
            return Some(folder_name);
        }
    }
    None
}

/// Build folder metadata for all folders that have published articles.
pub fn build_folder_metas(site: &Site) -> Vec<FolderMetaView> {
    let mut result = Vec::new();
    let published = site.published_articles();

    // Collect all tags per folder
    let mut folder_tags: HashMap<String, Vec<String>> = HashMap::new();
    let mut folder_counts: HashMap<String, usize> = HashMap::new();

    for article in &published {
        let count = folder_counts.entry(article.folder.clone()).or_insert(0);
        *count += 1;
        let tags = folder_tags.entry(article.folder.clone()).or_default();
        for tag in &article.tags {
            if !tags.contains(tag) {
                tags.push(tag.clone());
            }
        }
    }

    // Build folder metadata in deterministic order
    let mut folder_names: Vec<String> = folder_counts.keys().cloned().collect();
    folder_names.sort();
    // Move empty (root) to front
    if let Some(pos) = folder_names.iter().position(|n| n.is_empty()) {
        let root = folder_names.remove(pos);
        folder_names.insert(0, root);
    }

    for name in &folder_names {
        let slug = folder_to_slug(name);
        let count = folder_counts.get(name).copied().unwrap_or(0);
        let tags = folder_tags.get(name).cloned().unwrap_or_default();

        // Get article links for this folder
        let article_links: Vec<ArticleLink> = published
            .iter()
            .filter(|a| a.folder == *name)
            .map(|a| ArticleLink {
                slug: a.slug.clone(),
                title: a.title.clone(),
            })
            .collect();

        let (display_name, description, image_gradient, icon) =
            folder_display_meta(name, &tags, count);

        result.push(FolderMetaView {
            slug,
            name: name.clone(),
            display_name,
            description,
            image_gradient,
            icon,
            article_count: count,
            tags,
            articles: article_links,
        });
    }

    result
}

/// Build a directory tree for the given folder, grouping articles by subfolder.
pub fn build_folder_tree(
    root_folder: &str,
    published: &[&Article],
) -> (Vec<ArticleTreeItem>, Vec<TreeLine>) {
    let top_articles: Vec<ArticleTreeItem> = published
        .iter()
        .filter(|a| a.folder == root_folder)
        .map(|a| ArticleTreeItem {
            slug: a.slug.clone(),
            title: a.title.clone(),
            date: a.date.clone(),
        })
        .collect();

    let mut tree_lines = Vec::new();
    append_subtree(root_folder, published, 0, &mut tree_lines);

    (top_articles, tree_lines)
}

fn append_subtree(
    parent_folder: &str,
    published: &[&Article],
    depth: usize,
    lines: &mut Vec<TreeLine>,
) {
    let prefix = if parent_folder.is_empty() {
        String::new()
    } else {
        format!("{}/", parent_folder)
    };

    let mut child_map: BTreeMap<String, Vec<&Article>> = BTreeMap::new();
    for article in published {
        if article.folder == parent_folder {
            continue;
        }
        let rest = if prefix.is_empty() {
            Some(article.folder.as_str())
        } else {
            article.folder.strip_prefix(&prefix)
        };
        if let Some(rest) = rest {
            if rest.is_empty() {
                continue;
            }
            let first = rest.split('/').next().unwrap().to_string();
            child_map.entry(first).or_default().push(article);
        }
    }

    for (name, articles) in &child_map {
        let child_folder = if prefix.is_empty() {
            name.clone()
        } else {
            format!("{}{}", prefix, name)
        };

        lines.push(TreeLine {
            padding_left: format!("{}px", depth * 24),
            is_folder: true,
            name: name.clone(),
            slug: folder_to_slug(&child_folder),
            title: String::new(),
            date: String::new(),
        });

        for article in articles.iter().filter(|a| a.folder == child_folder) {
            lines.push(TreeLine {
                padding_left: format!("{}px", (depth + 1) * 24),
                is_folder: false,
                name: String::new(),
                slug: article.slug.clone(),
                title: article.title.clone(),
                date: article.date.clone(),
            });
        }

        append_subtree(&child_folder, published, depth + 1, lines);
    }
}

/// Auto-generate folder card display metadata from the directory name.
fn folder_display_meta(
    name: &str,
    _tags: &[String],
    _article_count: usize,
) -> (String, String, String, String) {
    let name = if name.is_empty() { "all" } else { name };
    let idx = (name
        .len()
        .wrapping_mul(7)
        .wrapping_add(name.bytes().fold(0u8, |a, b| a.wrapping_add(b)) as usize))
        % 12;
    let gradients = [
        "linear-gradient(135deg, #667eea 0%, #764ba2 100%)",
        "linear-gradient(135deg, #f093fb 0%, #f5576c 100%)",
        "linear-gradient(135deg, #4facfe 0%, #00f2fe 100%)",
        "linear-gradient(135deg, #43e97b 0%, #38f9d7 100%)",
        "linear-gradient(135deg, #fa709a 0%, #fee140 100%)",
        "linear-gradient(135deg, #a18cd1 0%, #fbc2eb 100%)",
        "linear-gradient(135deg, #6366f1 0%, #8b5cf6 100%)",
        "linear-gradient(135deg, #f12711 0%, #f5af19 100%)",
        "linear-gradient(135deg, #0c3483 0%, #a2b6df 100%)",
        "linear-gradient(135deg, #141E30 0%, #243B55 100%)",
        "linear-gradient(135deg, #11998e 0%, #38ef7d 100%)",
        "linear-gradient(135deg, #fc5c7d 0%, #6a82fb 100%)",
    ];
    let icons = [
        "📁", "📂", "📄", "📑", "📊", "📈", "📋", "📌", "📎", "📐", "📚", "📝",
    ];
    let gradient = gradients[idx].to_string();
    let icon = icons[idx].to_string();
    (name.to_string(), String::new(), gradient, icon)
}

async fn index_handler(State(state): State<AppState>) -> Result<Html<String>, AppError> {
    let site = state.site.read().await;

    let tags: Vec<TagView> = site
        .all_tags()
        .into_iter()
        .map(|(name, count)| TagView { name, count })
        .collect();

    let folder_groups = build_folder_groups(&site);
    let folders = build_folder_metas(&site);

    let tpl = IndexTemplate {
        folders,
        tags,
        folder_groups,
    };
    Ok(Html(tpl.render()?))
}

async fn folder_handler(
    State(state): State<AppState>,
    Path(slug): Path<String>,
) -> Result<Html<String>, AppError> {
    let site = state.site.read().await;
    let folder_name = slug_to_folder(&slug, &site).unwrap_or_else(|| slug.replace('-', " "));

    // Build folder meta
    let all_metas = build_folder_metas(&site);
    let folder_meta = all_metas.into_iter().find(|m| m.slug == slug);

    let mut folder_meta = match folder_meta {
        Some(m) => m,
        None => {
            // Create a basic one if not found
            let published: Vec<_> = site.published_articles();
            let prefix = if folder_name.is_empty() {
                String::new()
            } else {
                format!("{}/", folder_name)
            };
            let articles_in_folder: Vec<_> = published
                .iter()
                .filter(|a| a.folder == folder_name || a.folder.starts_with(&prefix))
                .collect();

            if articles_in_folder.is_empty() {
                return Err(AppError::NotFound(slug));
            }

            let (display_name, description, image_gradient, icon) =
                folder_display_meta(&folder_name, &[], articles_in_folder.len());

            FolderMetaView {
                slug: slug.clone(),
                name: folder_name.clone(),
                display_name,
                description,
                image_gradient,
                icon,
                article_count: articles_in_folder.len(),
                tags: Vec::new(),
                articles: Vec::new(),
            }
        }
    };

    let tags: Vec<TagView> = site
        .all_tags()
        .into_iter()
        .map(|(name, count)| TagView { name, count })
        .collect();

    let folder_groups = build_folder_groups(&site);

    let published_refs: Vec<&Article> = site.published_articles();

    // Count all articles including subfolders
    let prefix = if folder_meta.name.is_empty() {
        String::new()
    } else {
        format!("{}/", folder_meta.name)
    };
    let total_count = published_refs
        .iter()
        .filter(|a| a.folder == folder_meta.name || a.folder.starts_with(&prefix))
        .count();
    folder_meta.article_count = total_count;

    let (top_articles, tree_lines) = build_folder_tree(&folder_meta.name, &published_refs);

    let tpl = FolderTreeTemplate {
        folder: folder_meta,
        top_articles,
        tree_lines,
        tags,
        folder_groups,
    };
    Ok(Html(tpl.render()?))
}

async fn article_handler(
    State(state): State<AppState>,
    Path(slug): Path<String>,
) -> Result<Html<String>, AppError> {
    let slug = slug.trim_end_matches(".html").to_string();
    let site = state.site.read().await;
    match site.get_article(&slug) {
        Some(article) => {
            let view = ArticleView {
                slug: article.slug.clone(),
                title: article.title.clone(),
                folder: article.folder.clone(),
                tags: article.tags.clone(),
                date: article.date.clone(),
                content_html: article.content_html.clone(),
            };
            let folder_groups = build_folder_groups(&site);
            let tpl = ArticleTemplate {
                article: view,
                folder_groups,
            };
            Ok(Html(tpl.render()?))
        }
        None => Err(AppError::NotFound(slug)),
    }
}

async fn tag_handler(
    State(state): State<AppState>,
    Path(tag): Path<String>,
) -> Result<Html<String>, AppError> {
    let site = state.site.read().await;
    let articles: Vec<ArticleView> = site
        .get_articles_by_tag(&tag)
        .into_iter()
        .map(|a| ArticleView {
            slug: a.slug.clone(),
            title: a.title.clone(),
            folder: a.folder.clone(),
            tags: a.tags.clone(),
            date: a.date.clone(),
            content_html: truncate_html(&a.content_html, 300),
        })
        .collect();

    let folder_groups = build_folder_groups(&site);
    let tpl = TagTemplate {
        tag,
        articles,
        folder_groups,
    };
    Ok(Html(tpl.render()?))
}

async fn search_index_handler(State(state): State<AppState>) -> Json<Vec<SearchIndexEntry>> {
    let site = state.site.read().await;
    let entries: Vec<SearchIndexEntry> = site
        .published_articles()
        .into_iter()
        .map(|a| {
            let plain = strip_html(&a.content_html);
            let excerpt: String = plain.chars().take(500).collect();
            SearchIndexEntry {
                slug: a.slug.clone(),
                title: a.title.clone(),
                tags: a.tags.clone(),
                excerpt,
            }
        })
        .collect();
    Json(entries)
}

/// Strip HTML tags for plain-text excerpt.
pub(crate) fn strip_html(html: &str) -> String {
    let mut out = String::new();
    let mut in_tag = false;
    for ch in html.chars() {
        match ch {
            '<' => in_tag = true,
            '>' => in_tag = false,
            _ if !in_tag => out.push(ch),
            _ => {}
        }
    }
    // Collapse whitespace
    let re = out.split_whitespace().collect::<Vec<_>>();
    re.join(" ")
}

/// Truncate HTML to approximately `max_chars` visible characters.
pub(crate) fn truncate_html(html: &str, max_chars: usize) -> String {
    if html.len() <= max_chars {
        return html.to_string();
    }

    let mut out = String::new();
    let mut chars = 0;
    let mut in_tag = false;

    for ch in html.chars() {
        if ch == '<' {
            in_tag = true;
        }
        if !in_tag {
            if !ch.is_whitespace() {
                chars += 1;
            }
        }
        out.push(ch);
        if ch == '>' {
            in_tag = false;
        }
        if chars >= max_chars && !in_tag {
            out.push_str("…");
            break;
        }
    }

    out
}

/// Application error types
enum AppError {
    NotFound(String),
    Render(askama::Error),
}

impl From<askama::Error> for AppError {
    fn from(e: askama::Error) -> Self {
        AppError::Render(e)
    }
}

impl IntoResponse for AppError {
    fn into_response(self) -> Response {
        match self {
            AppError::NotFound(slug) => {
                Html(format!(
                    r#"<!DOCTYPE html><html><head><meta charset="utf-8"><title>404 - Not Found</title><link rel="stylesheet" href="/css/style.css"></head><body><main><h1>404</h1><p>Article "{}" not found.</p><a href="/">← Back to home</a></main></body></html>"#,
                    slug
                ))
                .into_response()
            }
            AppError::Render(e) => {
                tracing::error!("Template render error: {}", e);
                Html(
                    r#"<!DOCTYPE html><html><head><meta charset="utf-8"><title>500</title><link rel="stylesheet" href="/css/style.css"></head><body><main><h1>500</h1><p>Internal server error</p></main></body></html>"#
                        .to_string(),
                )
                .into_response()
            }
        }
    }
}

