use pulldown_cmark::{CodeBlockKind, Event, HeadingLevel, Options, Parser, Tag, TagEnd};
use std::collections::HashMap;
use std::sync::OnceLock;
use syntect::easy::HighlightLines;
use syntect::highlighting::ThemeSet;
use syntect::html::{IncludeBackground, styled_line_to_highlighted_html};
use syntect::parsing::SyntaxSet;
use syntect::util::LinesWithEndings;

/// Renders markdown to HTML with side-notes for footnote definitions
pub fn render_markdown<'a>(md: &'a str) -> String {
    let mut options = Options::empty();
    options.insert(Options::ENABLE_FOOTNOTES);
    options.insert(Options::ENABLE_TABLES);
    options.insert(Options::ENABLE_STRIKETHROUGH);
    options.insert(Options::ENABLE_TASKLISTS);
    options.insert(Options::ENABLE_HEADING_ATTRIBUTES);
    options.insert(Options::ENABLE_MATH);

    let parser = Parser::new_ext(md, options);
    let events: Vec<Event<'a>> = parser.collect();

    // Separate footnote definitions from main content
    let mut footnote_defs: HashMap<String, Vec<Event<'a>>> = HashMap::new();
    let mut content_events: Vec<Event<'a>> = Vec::new();
    let mut in_fn = false;
    let mut fn_name = String::new();
    let mut fn_events: Vec<Event<'a>> = Vec::new();

    for event in events {
        match &event {
            Event::Start(Tag::FootnoteDefinition(name)) => {
                in_fn = true;
                fn_name = name.to_string();
                fn_events.clear();
            }
            Event::End(TagEnd::FootnoteDefinition) => {
                in_fn = false;
                footnote_defs.insert(fn_name.clone(), fn_events.clone());
            }
            _ => {
                if in_fn {
                    fn_events.push(event);
                } else {
                    content_events.push(event);
                }
            }
        }
    }

    // Render content events into HTML
    let mut html = String::new();
    let mut active_footnotes: Vec<String> = Vec::new();
    let mut in_code_block = false;
    let mut code_lang = String::new();
    let mut code_content = String::new();
    let mut in_img = false;
    let mut img_url = String::new();
    let mut img_title = String::new();
    let mut img_alt = String::new();

    for event in content_events {
        match event {
            Event::Start(tag) => match tag {
                Tag::Paragraph => {
                    active_footnotes.clear();
                    html.push_str("<p>");
                }
                Tag::Heading { level, .. } => {
                    let h = heading_level_to_u32(level);
                    html.push_str(&format!("<h{}>", h));
                }
                Tag::BlockQuote(kind) => {
                    html.push_str("<blockquote>");
                    let _ = kind;
                }
                Tag::CodeBlock(kind) => {
                    code_lang = match kind {
                        CodeBlockKind::Fenced(info_string) => info_string
                            .split_whitespace()
                            .next()
                            .unwrap_or("")
                            .to_string(),
                        CodeBlockKind::Indented => String::new(),
                    };
                    in_code_block = true;
                    code_content.clear();
                }
                Tag::List(start) => {
                    if start.is_some() {
                        html.push_str("<ol>");
                    } else {
                        html.push_str("<ul>");
                    }
                }
                Tag::Item => {
                    html.push_str("<li>");
                }
                Tag::Table(_alignments) => {
                    html.push_str("<table>");
                }
                Tag::TableHead => {
                    html.push_str("<thead>");
                }
                Tag::TableRow => {
                    html.push_str("<tr>");
                }
                Tag::TableCell => {
                    html.push_str("<td>");
                }
                Tag::Emphasis => {
                    html.push_str("<em>");
                }
                Tag::Strong => {
                    html.push_str("<strong>");
                }
                Tag::Strikethrough => {
                    html.push_str("<del>");
                }
                Tag::Link {
                    dest_url, title, ..
                } => {
                    let title_attr = if title.is_empty() {
                        String::new()
                    } else {
                        format!(" title=\"{}\"", escape_attr(&title))
                    };
                    html.push_str(&format!(
                        "<a href=\"{}\"{}>",
                        escape_attr(&dest_url),
                        title_attr
                    ));
                }
                Tag::Image {
                    dest_url, title, ..
                } => {
                    in_img = true;
                    img_url = dest_url.to_string();
                    img_title = title.to_string();
                    img_alt.clear();
                }
                Tag::DefinitionList => {
                    html.push_str("<dl>");
                }
                Tag::DefinitionListTitle => {
                    html.push_str("<dt>");
                }
                Tag::DefinitionListDefinition => {
                    html.push_str("<dd>");
                }
                Tag::MetadataBlock(_) => {}
                _ => {}
            },
            Event::End(tag_end) => {
                let mut block_end = false;
                match &tag_end {
                    TagEnd::Paragraph => {
                        block_end = true;
                        html.push_str("</p>");
                    }
                    TagEnd::Heading(level) => {
                        block_end = true;
                        let h = heading_level_to_u32(*level);
                        html.push_str(&format!("</h{}>", h));
                    }
                    TagEnd::BlockQuote(_kind) => {
                        block_end = true;
                        html.push_str("</blockquote>");
                    }
                    TagEnd::CodeBlock => {
                        in_code_block = false;
                        if code_lang == "mermaid" {
                            html.push_str("<pre class=\"mermaid\">");
                            html.push_str(&code_content);
                            html.push_str("</pre>");
                        } else if !code_lang.is_empty() {
                            let dark =
                                highlight_code(&code_content, &code_lang, "base16-ocean.dark");
                            let light = highlight_code(&code_content, &code_lang, "InspiredGitHub");
                            html.push_str(&format!(
                                "<pre class=\"code-block-dark\"><code class=\"language-{}\">",
                                code_lang
                            ));
                            html.push_str(&dark);
                            html.push_str("</code></pre>");
                            html.push_str(&format!(
                                "<pre class=\"code-block-light\"><code class=\"language-{}\">",
                                code_lang
                            ));
                            html.push_str(&light);
                            html.push_str("</code></pre>");
                        } else {
                            html.push_str("<pre><code>");
                            html.push_str(&escape_html(&code_content));
                            html.push_str("</code></pre>");
                        }
                    }
                    TagEnd::List(false) => {
                        html.push_str("</ul>");
                    }
                    TagEnd::List(true) => {
                        html.push_str("</ol>");
                    }
                    TagEnd::Item => {
                        block_end = true;
                        html.push_str("</li>");
                    }
                    TagEnd::Table => {
                        block_end = true;
                        html.push_str("</table>");
                    }
                    TagEnd::TableHead => {
                        html.push_str("</thead>");
                    }
                    TagEnd::TableRow => {
                        html.push_str("</tr>");
                    }
                    TagEnd::TableCell => {
                        block_end = true;
                        html.push_str("</td>");
                    }
                    TagEnd::Emphasis => {
                        html.push_str("</em>");
                    }
                    TagEnd::Strong => {
                        html.push_str("</strong>");
                    }
                    TagEnd::Strikethrough => {
                        html.push_str("</del>");
                    }
                    TagEnd::Link => {
                        html.push_str("</a>");
                    }
                    TagEnd::Image => {
                        in_img = false;
                        let title_attr = if img_title.is_empty() {
                            String::new()
                        } else {
                            format!(" title=\"{}\"", escape_attr(&img_title))
                        };
                        html.push_str(&format!(
                            "<img src=\"{}\"{} alt=\"{}\" />",
                            escape_attr(&img_url),
                            title_attr,
                            escape_attr(&img_alt)
                        ));
                    }
                    TagEnd::DefinitionList => {
                        block_end = true;
                        html.push_str("</dl>");
                    }
                    TagEnd::DefinitionListTitle => {
                        html.push_str("</dt>");
                    }
                    TagEnd::DefinitionListDefinition => {
                        block_end = true;
                        html.push_str("</dd>");
                    }
                    TagEnd::MetadataBlock(_) => {}
                    _ => {}
                }
                if block_end {
                    for name in &active_footnotes {
                        if let Some(events) = footnote_defs.get(name) {
                            html.push_str(&format!(
                                "<aside class=\"footnote-side\" id=\"fn-{}\">",
                                name
                            ));
                            html.push_str("<sup class=\"fn-marker\">");
                            html.push_str(name);
                            html.push_str("</sup> ");
                            html.push_str(&render_footnote_events(events));
                            html.push_str("</aside>");
                        }
                    }
                    active_footnotes.clear();
                }
            }
            Event::Text(text) => {
                if in_code_block {
                    code_content.push_str(&text);
                } else if in_img {
                    img_alt.push_str(&text);
                } else {
                    html.push_str(&escape_html(&text));
                }
            }
            Event::Code(text) => {
                html.push_str(&format!("<code>{}</code>", escape_html(&text)));
            }
            Event::Html(html_raw) => {
                if in_code_block {
                    code_content.push_str(&html_raw);
                } else {
                    html.push_str(&html_raw);
                }
            }
            Event::SoftBreak => {
                if in_code_block {
                    code_content.push('\n');
                } else {
                    html.push(' ');
                }
            }
            Event::HardBreak => {
                html.push_str("<br />\n");
            }
            Event::Rule => {
                html.push_str("<hr />\n");
            }
            Event::TaskListMarker(checked) => {
                if checked {
                    html.push_str("<input type=\"checkbox\" checked disabled />");
                } else {
                    html.push_str("<input type=\"checkbox\" disabled />");
                }
            }
            Event::InlineHtml(html_raw) => {
                html.push_str(&html_raw);
            }
            Event::InlineMath(math) => {
                html.push_str(&format!("\\({}\\)", math));
            }
            Event::DisplayMath(math) => {
                html.push_str(&format!("\\[{}\\]", math));
            }
            Event::FootnoteReference(name) => {
                html.push_str(&format!(
                    "<sup class=\"footnote-ref\" id=\"fnref-{}\"><a href=\"#fn-{}\">[{}]</a></sup>",
                    name, name, name
                ));
                active_footnotes.push(name.to_string());
            }
        }
    }

    html
}

fn heading_level_to_u32(level: HeadingLevel) -> u32 {
    match level {
        HeadingLevel::H1 => 1,
        HeadingLevel::H2 => 2,
        HeadingLevel::H3 => 3,
        HeadingLevel::H4 => 4,
        HeadingLevel::H5 => 5,
        HeadingLevel::H6 => 6,
    }
}

/// Render footnote content events to HTML string
fn render_footnote_events(events: &[Event]) -> String {
    let mut html = String::new();

    for event in events {
        match event {
            Event::Start(tag) => match tag {
                Tag::Paragraph => html.push_str("<span class=\"fn-text\">"),
                Tag::Emphasis => html.push_str("<em>"),
                Tag::Strong => html.push_str("<strong>"),
                Tag::Strikethrough => html.push_str("<del>"),
                Tag::CodeBlock(_) => html.push_str("<code>"),
                Tag::Link {
                    dest_url, title, ..
                } => {
                    let title_attr = if title.is_empty() {
                        String::new()
                    } else {
                        format!(" title=\"{}\"", escape_attr(title))
                    };
                    html.push_str(&format!(
                        "<a href=\"{}\"{}>",
                        escape_attr(dest_url),
                        title_attr
                    ));
                }
                Tag::List(_) => html.push_str("<ul>"),
                Tag::Item => html.push_str("<li>"),
                _ => {}
            },
            Event::End(tag_end) => match tag_end {
                TagEnd::Paragraph => html.push_str("</span>"),
                TagEnd::Emphasis => html.push_str("</em>"),
                TagEnd::Strong => html.push_str("</strong>"),
                TagEnd::Strikethrough => html.push_str("</del>"),
                TagEnd::CodeBlock => html.push_str("</code>"),
                TagEnd::Link => html.push_str("</a>"),
                TagEnd::List(_) => html.push_str("</ul>"),
                TagEnd::Item => html.push_str("</li>"),
                _ => {}
            },
            Event::Text(text) => html.push_str(&escape_html(text)),
            Event::Code(text) => html.push_str(&format!("<code>{}</code>", escape_html(text))),
            Event::SoftBreak => html.push(' '),
            Event::HardBreak => html.push_str("<br />"),
            Event::Html(html_raw) => html.push_str(html_raw),
            _ => {}
        }
    }

    html
}

fn highlight_code(code: &str, lang: &str, theme_name: &str) -> String {
    let ss = get_syntax_set();
    let Some(syntax) = ss.find_syntax_by_token(lang) else {
        return escape_html(code);
    };
    let ts = get_theme_set();
    let theme = &ts.themes[theme_name];

    let mut highlighter = HighlightLines::new(syntax, theme);
    let mut result = String::new();
    for line in LinesWithEndings::from(code) {
        if let Ok(ranges) = highlighter.highlight_line(line, ss) {
            if let Ok(html) = styled_line_to_highlighted_html(&ranges, IncludeBackground::No) {
                result.push_str(&html);
            }
        }
    }
    result
}

fn get_syntax_set() -> &'static SyntaxSet {
    static SS: OnceLock<SyntaxSet> = OnceLock::new();
    SS.get_or_init(|| SyntaxSet::load_defaults_newlines())
}

fn get_theme_set() -> &'static ThemeSet {
    static TS: OnceLock<ThemeSet> = OnceLock::new();
    TS.get_or_init(|| ThemeSet::load_defaults())
}

fn escape_html(s: &str) -> String {
    s.replace('&', "&amp;")
        .replace('<', "&lt;")
        .replace('>', "&gt;")
        .replace('"', "&quot;")
}

fn escape_attr(s: &str) -> String {
    s.replace('&', "&amp;")
        .replace('"', "&quot;")
        .replace('<', "&lt;")
        .replace('>', "&gt;")
}


