async fn search_index_handler(State(state): State<AppState>) -> Json<Vec<SearchIndexEntry>> {
    let site = state.site.read().await;
    let entries: Vec<SearchIndexEntry> = site
        .published_articles()
        .into_iter()
        .map(|a| {
            let plain = strip_html(&a.content_html);
            let excerpt: String = plain.chars().take(500).collect();
            SearchIndexEntry {
                slug: a.slug.clone(),
                title: a.title.clone(),
                tags: a.tags.clone(),
                excerpt,
            }
        })
        .collect();
    Json(entries)
}

/// Strip HTML tags for plain-text excerpt.
pub(crate) fn strip_html(html: &str) -> String {
    let mut out = String::new();
    let mut in_tag = false;
    for ch in html.chars() {
        match ch {
            '<' => in_tag = true,
            '>' => in_tag = false,
            _ if !in_tag => out.push(ch),
            _ => {}
        }
    }
    // Collapse whitespace
    let re = out.split_whitespace().collect::<Vec<_>>();
    re.join(" ")
}

/// Truncate HTML to approximately `max_chars` visible characters.
pub(crate) fn truncate_html(html: &str, max_chars: usize) -> String {
    if html.len() <= max_chars {
        return html.to_string();
    }

    let mut out = String::new();
    let mut chars = 0;
    let mut in_tag = false;

    for ch in html.chars() {
        if ch == '<' {
            in_tag = true;
        }
        if !in_tag {
            if !ch.is_whitespace() {
                chars += 1;
            }
        }
        out.push(ch);
        if ch == '>' {
            in_tag = false;
        }
        if chars >= max_chars && !in_tag {
            out.push_str("…");
            break;
        }
    }

    out
}

/// Application error types
enum AppError {
    NotFound(String),
    Render(askama::Error),
}

impl From<askama::Error> for AppError {
    fn from(e: askama::Error) -> Self {
        AppError::Render(e)
    }
}

impl IntoResponse for AppError {
    fn into_response(self) -> Response {
        match self {
            AppError::NotFound(slug) => {
                Html(format!(
                    r#"<!DOCTYPE html><html><head><meta charset="utf-8"><title>404 - Not Found</title><link rel="stylesheet" href="/css/style.css"></head><body><main><h1>404</h1><p>Article "{}" not found.</p><a href="/">← Back to home</a></main></body></html>"#,
                    slug
                ))
                .into_response()
            }
            AppError::Render(e) => {
                tracing::error!("Template render error: {}", e);
                Html(
                    r#"<!DOCTYPE html><html><head><meta charset="utf-8"><title>500</title><link rel="stylesheet" href="/css/style.css"></head><body><main><h1>500</h1><p>Internal server error</p></main></body></html>"#
                        .to_string(),
                )
                .into_response()
            }
        }
    }
}


