use crate::article::{Article, parse_article};
use anyhow::Result;
use notify::{Event, EventKind, RecursiveMode, Watcher};
use std::collections::{BTreeMap, BTreeSet, HashMap};
use std::path::{Path, PathBuf};
use std::sync::Arc;
use tokio::sync::RwLock;
use tracing::info;

/// The site holds all loaded articles in memory.
pub struct Site {
    articles: Vec<Article>,
    slug_index: HashMap<String, usize>,
    tag_index: HashMap<String, Vec<usize>>,
    /// Articles grouped by folder: (folder_name, [article_index, ...])
    folder_groups: Vec<(String, Vec<usize>)>,
}

impl Site {
    fn new(articles: Vec<Article>) -> Self {
        let mut slug_index = HashMap::new();
        let mut tag_index: HashMap<String, Vec<usize>> = HashMap::new();
        // BTreeMap for deterministic folder ordering
        let mut folders: BTreeMap<String, Vec<usize>> = BTreeMap::new();

        for (i, article) in articles.iter().enumerate() {
            slug_index.insert(article.slug.clone(), i);
            for tag in &article.tags {
                tag_index.entry(tag.clone()).or_default().push(i);
            }
            folders.entry(article.folder.clone()).or_default().push(i);
        }

        // Build ordered folder groups: root (empty) first, then alphabetically
        let mut folder_groups = Vec::with_capacity(folders.len());
        if let Some(root) = folders.remove("") {
            folder_groups.push((String::new(), root));
        }
        for (name, indices) in folders {
            folder_groups.push((name, indices));
        }

        Self {
            articles,
            slug_index,
            tag_index,
            folder_groups,
        }
    }

    pub fn published_articles(&self) -> Vec<&Article> {
        self.articles.iter().filter(|a| !a.draft).collect()
    }

    pub fn get_article(&self, slug: &str) -> Option<&Article> {
        self.slug_index.get(slug).map(|&i| &self.articles[i])
    }

    pub fn get_articles_by_tag(&self, tag: &str) -> Vec<&Article> {
        self.tag_index
            .get(tag)
            .map(|indices| {
                indices
                    .iter()
                    .filter_map(|&i| {
                        let a = &self.articles[i];
                        if !a.draft { Some(a) } else { None }
                    })
                    .collect()
            })
            .unwrap_or_default()
    }

    pub fn all_tags(&self) -> BTreeSet<(String, usize)> {
        let mut tag_counts: HashMap<String, usize> = HashMap::new();
        for article in &self.articles {
            if article.draft {
                continue;
            }
            for tag in &article.tags {
                *tag_counts.entry(tag.clone()).or_default() += 1;
            }
        }
        let mut result: BTreeSet<(String, usize)> = BTreeSet::new();
        for (tag, count) in tag_counts {
            result.insert((tag, count));
        }
        result
    }

    /// Returns folder groups with published articles.
    /// Each group is (folder_name, Vec<&Article>). Root (empty) comes first.
    pub fn folder_groups(&self) -> Vec<(String, Vec<&Article>)> {
        self.folder_groups
            .iter()
            .map(|(name, indices)| {
                let articles: Vec<&Article> = indices
                    .iter()
                    .filter_map(|&i| {
                        let a = &self.articles[i];
                        if !a.draft { Some(a) } else { None }
                    })
                    .collect();
                (name.clone(), articles)
            })
            .filter(|(_, articles)| !articles.is_empty())
            .collect()
    }
}

/// Load all markdown content from the given directory.
pub fn load_content(content_dir: &Path) -> Result<Site> {
    let mut articles = Vec::new();

    if !content_dir.exists() {
        info!(
            "Content directory {:?} does not exist, creating it",
            content_dir
        );
        std::fs::create_dir_all(content_dir)?;
        return Ok(Site::new(articles));
    }

    let mut entries: Vec<PathBuf> = Vec::new();
    collect_md_files(content_dir, &mut entries)?;
    entries.sort();

    for path in &entries {
        let raw = std::fs::read_to_string(path)?;
        match parse_article(path, content_dir, &raw) {
            Ok(article) => {
                info!("Loaded article: {}", article.title);
                articles.push(article);
            }
            Err(e) => {
                tracing::warn!("Failed to parse {:?}: {}", path, e);
            }
        }
    }

    Ok(Site::new(articles))
}

fn collect_md_files(dir: &Path, out: &mut Vec<PathBuf>) -> Result<()> {
    for entry in std::fs::read_dir(dir)? {
        let entry = entry?;
        let path = entry.path();
        if path.is_dir() {
            collect_md_files(&path, out)?;
        } else if path.extension().and_then(|s| s.to_str()) == Some("md") {
            out.push(path);
        }
    }
    Ok(())
}

/// Start a file watcher that reloads content on change.
pub fn start_file_watcher(content_dir: PathBuf, site: Arc<RwLock<Site>>) -> Result<impl Watcher> {
    let watch_dir = content_dir.clone();
    let mut watcher = notify::recommended_watcher(move |res: Result<Event, notify::Error>| {
        if let Ok(event) = res {
            if matches!(
                event.kind,
                EventKind::Create(_) | EventKind::Modify(_) | EventKind::Remove(_)
            ) {
                info!("Content directory changed, reloading...");
                if let Ok(new_site) = load_content(&watch_dir) {
                    let mut site = site.blocking_write();
                    *site = new_site;
                    info!("Content reloaded");
                }
            }
        }
    })?;

    watcher.watch(&content_dir, RecursiveMode::Recursive)?;
    Ok(watcher)
}

