    let tags = fm.tags.clone().unwrap_or_default();
    let draft = fm.draft.unwrap_or(false);
    let date = fm.date.clone().unwrap_or_default();

    let content_html = render_markdown(body);

    Ok(Article {
        slug,
        title,
        folder,
        tags,
        draft,
        date,
        content_html,
    })
}

