use crate::content::Site;
use crate::routes::{
    ArticleTemplate, ArticleView, FolderTreeTemplate, IndexTemplate,
    SearchIndexEntry, TagTemplate, TagView,
    build_folder_groups, build_folder_metas, build_folder_tree, strip_html, truncate_html,
};
use anyhow::Result;
use askama::Template;
use std::path::Path;
use tracing::info;

pub fn export_site(site: &Site, static_dir: &Path, output_dir: &Path) -> Result<()> {
    info!("Exporting static site to {:?}", output_dir);

    let article_dir = output_dir.join("article");
    let tag_dir = output_dir.join("tag");
    let folder_dir = output_dir.join("folder");
    std::fs::create_dir_all(&article_dir)?;
    std::fs::create_dir_all(&tag_dir)?;
    std::fs::create_dir_all(&folder_dir)?;

    let folder_groups = build_folder_groups(site);
    let published = site.published_articles();

    let tags: Vec<TagView> = site
        .all_tags()
        .into_iter()
        .map(|(name, count)| TagView { name, count })
        .collect();

    // Index page
    info!("Generating index.html");
    let folders = build_folder_metas(site);
    let tpl = IndexTemplate {
        folders,
        tags: tags.clone(),
        folder_groups: folder_groups.clone(),
    };
    std::fs::write(output_dir.join("index.html"), tpl.render()?)?;

    // Article pages
    for article in &published {
        info!("Generating article/{}.html", article.slug);
        let view = ArticleView {
            slug: article.slug.clone(),
            title: article.title.clone(),
            folder: article.folder.clone(),
            tags: article.tags.clone(),
            date: article.date.clone(),
            content_html: article.content_html.clone(),
        };
        let tpl = ArticleTemplate {
            article: view,
            folder_groups: folder_groups.clone(),
        };
        let filename = format!("{}.html", article.slug);
        std::fs::write(article_dir.join(&filename), tpl.render()?)?;
    }

    // Tag pages
    for (tag_name, _) in site.all_tags() {
        info!("Generating tag/{}.html", tag_name);
        let tagged: Vec<ArticleView> = site
            .get_articles_by_tag(&tag_name)
            .into_iter()
            .map(|a| ArticleView {
                slug: a.slug.clone(),
                title: a.title.clone(),
                folder: a.folder.clone(),
                tags: a.tags.clone(),
                date: a.date.clone(),
                content_html: truncate_html(&a.content_html, 300),
            })
            .collect();

        let tpl = TagTemplate {
            tag: tag_name.clone(),
            articles: tagged,
            folder_groups: folder_groups.clone(),
        };
        let filename = format!("{}.html", tag_name);
        std::fs::write(tag_dir.join(&filename), tpl.render()?)?;
    }

    // Folder pages
    let all_metas = build_folder_metas(site);
    for folder_meta in &all_metas {
        if folder_meta.name.is_empty() {
            continue;
        }
        info!("Generating folder/{}.html", folder_meta.slug);

        let (top_articles, tree_lines) = build_folder_tree(&folder_meta.name, &published);

        let tpl = FolderTreeTemplate {
            folder: folder_meta.clone(),
            top_articles,
            tree_lines,
            tags: tags.clone(),
            folder_groups: folder_groups.clone(),
        };
        let filename = format!("{}.html", folder_meta.slug);
        let out_path = folder_dir.join(&filename);
        if let Some(parent) = out_path.parent() {
            std::fs::create_dir_all(parent)?;
        }
        std::fs::write(out_path, tpl.render()?)?;
    }

    // Search index
    info!("Generating search-index.json");
    let search_entries: Vec<SearchIndexEntry> = published
        .iter()
        .map(|a| {
            let plain = strip_html(&a.content_html);
            let excerpt: String = plain.chars().take(500).collect();
            SearchIndexEntry {
                slug: a.slug.clone(),
                title: a.title.clone(),
                tags: a.tags.clone(),
                excerpt,
            }
        })
        .collect();
    let json = serde_json::to_string_pretty(&search_entries)?;
    std::fs::write(output_dir.join("search-index.json"), &json)?;

    // Copy static assets
    info!("Copying static assets from {:?}", static_dir);
    copy_dir(static_dir, output_dir)?;

    info!("Static site exported to {:?}", output_dir);
    Ok(())
}

fn copy_dir(src: &Path, dst: &Path) -> Result<()> {
    for entry in std::fs::read_dir(src)? {
        let entry = entry?;
        let path = entry.path();
        let relative = path.strip_prefix(src)?;
        let dest = dst.join(relative);
        if path.is_dir() {
            std::fs::create_dir_all(&dest)?;
            copy_dir(&path, &dest)?;
        } else {
            std::fs::copy(&path, &dest)?;
        }
    }
    Ok(())
}

