// Audit script: verify README behavior
// This is a standalone script that reproduces the build's test patterns
// and tests edge cases not covered by existing tests.
// Run with: cargo test --bin mizushi 2>&1 | grep -E "^(test |.*FAILED|test result)"

// The issues we're checking are:
// 1. search_index_handler includes README articles
// 2. export.rs generates article pages for READMEs
// 3. build_folder_groups includes READMEs in navigation
// 4. tag pages include README articles if they have tags

fn main() {
    println!("Audit scoping script - see analysis in audit report");
    println!("Issues identified by code inspection:\n");
