mod tests {
    use super::*;
    use crate::article::Article;
    use crate::content::Site;

    fn make_article(slug: &str, folder: &str, title: &str, content: &str) -> Article {
        Article {
            slug: slug.to_string(),
            title: title.to_string(),
            folder: folder.to_string(),
            tags: vec![],
            draft: false,
            date: String::new(),
            content_html: content.to_string(),
        }
    }

    #[test]
    fn test_is_readme() {
        assert!(is_readme(&make_article("README", "rust", "Readme", "<p>desc</p>")));
        assert!(is_readme(&make_article("readme", "", "Readme", "<p>desc</p>")));
        assert!(is_readme(&make_article("reame", "", "Reame", "<p>typo</p>")));
        assert!(is_readme(&make_article("REAME", "rust", "Reame", "<p>typo</p>")));
        assert!(!is_readme(&make_article("guide", "rust", "Guide", "<p>body</p>")));
        assert!(!is_readme(&make_article("readme-guide", "", "Guide", "<p>body</p>")));
    }

    #[test]
    fn test_build_folder_metas_excludes_readme() {
        let articles = vec![
            make_article("README", "rust", "Readme", "<p>README content</p>"),
            make_article("guide", "rust", "Rust Guide", "<p>body</p>"),
            make_article("intro", "", "Intro", "<p>root</p>"),
        ];
        let site = Site::_new_for_test(articles);
        let metas = build_folder_metas(&site);

        let rust_meta = metas.iter().find(|m| m.slug == "rust").unwrap();
        assert_eq!(rust_meta.article_count, 1, "README excluded from count");
        assert_eq!(rust_meta.description, "<p>README content</p>", "README HTML becomes description");
        assert_eq!(rust_meta.articles.len(), 1, "only non-README in links");
        assert_eq!(rust_meta.articles[0].title, "Rust Guide");
    }

    #[test]
    fn test_build_folder_tree_excludes_readme() {
        let articles = vec![
            make_article("README", "rust", "Readme", "<p>desc</p>"),
            make_article("guide", "rust", "Rust Guide", "<p>body</p>"),
            make_article("nested", "rust/advanced", "Advanced", "<p>nested</p>"),
        ];
        let site = Site::_new_for_test(articles);
        let published: Vec<&Article> = site.published_articles();

        let (top_articles, tree_lines) = build_folder_tree("rust", &published);
