pub fn router(state: AppState) -> Router {
    Router::new()
        .route("/", get(index_handler))
        .route("/article/{slug}", get(article_handler))
        .route("/tag/{tag}", get(tag_handler))
        .route("/folder/{*slug}", get(folder_handler))
