use crate::article::{Article, parse_article};
use anyhow::Result;
use notify::{Event, EventKind, RecursiveMode, Watcher};
use std::collections::{BTreeMap, BTreeSet, HashMap};
use std::path::{Path, PathBuf};
use std::sync::Arc;
use tokio::sync::RwLock;
use tracing::info;

/// The site holds all loaded articles in memory.
pub struct Site {
    articles: Vec<Article>,
    slug_index: HashMap<String, usize>,
    tag_index: HashMap<String, Vec<usize>>,
    /// Articles grouped by folder: (folder_name, [article_index, ...])
    folder_groups: Vec<(String, Vec<usize>)>,
}

impl Site {
    fn new(articles: Vec<Article>) -> Self {
        Self::_new_for_test(articles)
    }

    /// Public constructor for testing only.
    #[doc(hidden)]
    pub fn _new_for_test(articles: Vec<Article>) -> Self {
        let mut slug_index = HashMap::new();
        let mut tag_index: HashMap<String, Vec<usize>> = HashMap::new();
        // BTreeMap for deterministic folder ordering
        let mut folders: BTreeMap<String, Vec<usize>> = BTreeMap::new();

        for (i, article) in articles.iter().enumerate() {
            slug_index.insert(article.slug.clone(), i);
            for tag in &article.tags {
                tag_index.entry(tag.clone()).or_default().push(i);
            }
            folders.entry(article.folder.clone()).or_default().push(i);
        }

        // Build ordered folder groups: root (empty) first, then alphabetically
        let mut folder_groups = Vec::with_capacity(folders.len());
        if let Some(root) = folders.remove("") {
            folder_groups.push((String::new(), root));
        }
        for (name, indices) in folders {
            folder_groups.push((name, indices));
        }

        Self {
            articles,
            slug_index,
            tag_index,
            folder_groups,
        }
    }

    pub fn published_articles(&self) -> Vec<&Article> {
        self.articles.iter().filter(|a| !a.draft).collect()
    }

    pub fn get_article(&self, slug: &str) -> Option<&Article> {
        self.slug_index.get(slug).map(|&i| &self.articles[i])
    }

    pub fn get_articles_by_tag(&self, tag: &str) -> Vec<&Article> {
        self.tag_index
            .get(tag)
            .map(|indices| {
                indices
                    .iter()
                    .filter_map(|&i| {
                        let a = &self.articles[i];
                        if !a.draft { Some(a) } else { None }
                    })
                    .collect()
            })
            .unwrap_or_default()
    }

    pub fn all_tags(&self) -> BTreeSet<(String, usize)> {
        let mut tag_counts: HashMap<String, usize> = HashMap::new();
        for article in &self.articles {
            if article.draft {
                continue;
            }
            for tag in &article.tags {
                *tag_counts.entry(tag.clone()).or_default() += 1;
            }
        }
        let mut result: BTreeSet<(String, usize)> = BTreeSet::new();
        for (tag, count) in tag_counts {
            result.insert((tag, count));
        }
        result
    }

    /// Returns folder groups with published articles.
    /// Each group is (folder_name, Vec<&Article>). Root (empty) comes first.
    pub fn folder_groups(&self) -> Vec<(String, Vec<&Article>)> {
        self.folder_groups
            .iter()
            .map(|(name, indices)| {
                let articles: Vec<&Article> = indices
                    .iter()
                    .filter_map(|&i| {
                        let a = &self.articles[i];
                        if !a.draft { Some(a) } else { None }
                    })
                    .collect();
                (name.clone(), articles)
            })
            .filter(|(_, articles)| !articles.is_empty())
            .collect()
    }
}

/// Load all markdown content from the given directory.
pub fn load_content(content_dir: &Path) -> Result<Site> {
    let mut articles = Vec::new();

    if !content_dir.exists() {
        info!(
            "Content directory {:?} does not exist, creating it",
            content_dir
        );
        std::fs::create_dir_all(content_dir)?;
        return Ok(Site::new(articles));
    }

    let mut entries: Vec<PathBuf> = Vec::new();
    collect_md_files(content_dir, &mut entries)?;
    entries.sort();

    for path in &entries {
        let raw = std::fs::read_to_string(path)?;
        match parse_article(path, content_dir, &raw) {
            Ok(article) => {
                info!("Loaded article: {}", article.title);
                articles.push(article);
            }
            Err(e) => {
                tracing::warn!("Failed to parse {:?}: {}", path, e);
            }
        }
    }

    Ok(Site::new(articles))
}

fn collect_md_files(dir: &Path, out: &mut Vec<PathBuf>) -> Result<()> {
    for entry in std::fs::read_dir(dir)? {
        let entry = entry?;
        let path = entry.path();
        if path.is_dir() {
            collect_md_files(&path, out)?;
        } else if path.extension().and_then(|s| s.to_str()) == Some("md") {
            out.push(path);
        }
    }
    Ok(())
}

/// Start a file watcher that reloads content on change.
pub fn start_file_watcher(content_dir: PathBuf, site: Arc<RwLock<Site>>) -> Result<impl Watcher> {
    let watch_dir = content_dir.clone();
    let mut watcher = notify::recommended_watcher(move |res: Result<Event, notify::Error>| {
        if let Ok(event) = res {
            if matches!(
                event.kind,
                EventKind::Create(_) | EventKind::Modify(_) | EventKind::Remove(_)
            ) {
                info!("Content directory changed, reloading...");
                if let Ok(new_site) = load_content(&watch_dir) {
                    let mut site = site.blocking_write();
                    *site = new_site;
                    info!("Content reloaded");
                }
            }
        }
    })?;

    watcher.watch(&content_dir, RecursiveMode::Recursive)?;
    Ok(watcher)
}

use crate::content::Site;
use crate::routes::{
    ArticleTemplate, ArticleView, FolderTreeTemplate, IndexTemplate,
    SearchIndexEntry, TagTemplate, TagView,
    build_folder_groups, build_folder_metas, build_folder_tree, is_readme, strip_html, truncate_html,
};
use anyhow::Result;
use askama::Template;
use std::path::Path;
use tracing::info;

pub fn export_site(site: &Site, static_dir: &Path, output_dir: &Path) -> Result<()> {
    info!("Exporting static site to {:?}", output_dir);

    let article_dir = output_dir.join("article");
    let tag_dir = output_dir.join("tag");
    let folder_dir = output_dir.join("folder");
    std::fs::create_dir_all(&article_dir)?;
    std::fs::create_dir_all(&tag_dir)?;
    std::fs::create_dir_all(&folder_dir)?;

    let folder_groups = build_folder_groups(site);
    let published = site.published_articles();

    let tags: Vec<TagView> = site
        .all_tags()
        .into_iter()
        .map(|(name, count)| TagView { name, count })
        .collect();

    // Index page
    info!("Generating index.html");
    let folders = build_folder_metas(site);
    let tpl = IndexTemplate {
        folders,
        tags: tags.clone(),
        folder_groups: folder_groups.clone(),
    };
    std::fs::write(output_dir.join("index.html"), tpl.render()?)?;

    // Article pages
    for article in published.iter().filter(|a| !is_readme(*a)) {
        info!("Generating article/{}.html", article.slug);
        let view = ArticleView {
            slug: article.slug.clone(),
            title: article.title.clone(),
            folder: article.folder.clone(),
            tags: article.tags.clone(),
            date: article.date.clone(),
            content_html: article.content_html.clone(),
        };
        let tpl = ArticleTemplate {
            article: view,
            folder_groups: folder_groups.clone(),
        };
        let filename = format!("{}.html", article.slug);
        std::fs::write(article_dir.join(&filename), tpl.render()?)?;
    }

    // Tag pages
    for (tag_name, _) in site.all_tags() {
        info!("Generating tag/{}.html", tag_name);
        let tagged: Vec<ArticleView> = site
            .get_articles_by_tag(&tag_name)
            .into_iter()
            .map(|a| ArticleView {
                slug: a.slug.clone(),
                title: a.title.clone(),
                folder: a.folder.clone(),
                tags: a.tags.clone(),
                date: a.date.clone(),
                content_html: truncate_html(&a.content_html, 300),
            })
            .collect();

        let tpl = TagTemplate {
            tag: tag_name.clone(),
            articles: tagged,
            folder_groups: folder_groups.clone(),
        };
        let filename = format!("{}.html", tag_name);
        std::fs::write(tag_dir.join(&filename), tpl.render()?)?;
    }

    // Folder pages
    let all_metas = build_folder_metas(site);
    for folder_meta in &all_metas {
        if folder_meta.name.is_empty() {
            continue;
        }
        info!("Generating folder/{}.html", folder_meta.slug);

        let (top_articles, tree_lines) = build_folder_tree(&folder_meta.name, &published);

        let tpl = FolderTreeTemplate {
            folder: folder_meta.clone(),
            top_articles,
            tree_lines,
            tags: tags.clone(),
            folder_groups: folder_groups.clone(),
        };
        let filename = format!("{}.html", folder_meta.slug);
        let out_path = folder_dir.join(&filename);
        if let Some(parent) = out_path.parent() {
            std::fs::create_dir_all(parent)?;
        }
        std::fs::write(out_path, tpl.render()?)?;
    }

    // Search index
    info!("Generating search-index.json");
    let search_entries: Vec<SearchIndexEntry> = published
        .iter()
        .filter(|a| !is_readme(*a))
        .map(|a| {
            let plain = strip_html(&a.content_html);
            let excerpt: String = plain.chars().take(500).collect();
            SearchIndexEntry {
                slug: a.slug.clone(),
                title: a.title.clone(),
                tags: a.tags.clone(),
                excerpt,
            }
        })
        .collect();
    let json = serde_json::to_string_pretty(&search_entries)?;
    std::fs::write(output_dir.join("search-index.json"), &json)?;

    // Copy static assets
    info!("Copying static assets from {:?}", static_dir);
    copy_dir(static_dir, output_dir)?;

    info!("Static site exported to {:?}", output_dir);
    Ok(())
}

fn copy_dir(src: &Path, dst: &Path) -> Result<()> {
    for entry in std::fs::read_dir(src)? {
        let entry = entry?;
        let path = entry.path();
        let relative = path.strip_prefix(src)?;
        let dest = dst.join(relative);
        if path.is_dir() {
            std::fs::create_dir_all(&dest)?;
            copy_dir(&path, &dest)?;
        } else {
            std::fs::copy(&path, &dest)?;
        }
    }
    Ok(())
}

