pub(crate) fn build_folder_groups(site: &Site) -> Vec<FolderGroup> {
    let groups = site.folder_groups();
    let mut by_path: std::collections::BTreeMap<String, Vec<ArticleLink>> =
        std::collections::BTreeMap::new();
    for (path, articles) in groups {
        let links: Vec<ArticleLink> = articles
            .into_iter()
            .filter(|a| !is_readme(*a))
            .map(|a| ArticleLink {
                slug: a.slug.clone(),
                title: a.title.clone(),
            })
            .collect();
        by_path.entry(path).or_default().extend(links);
    }

    let root_articles = by_path.remove("").unwrap_or_default();
    let mut result = flatten_subtrees(&by_path, "", 0);

    if !root_articles.is_empty() {
        result.insert(
            0,
            FolderGroup {
                name: String::new(),
                slug: String::new(),
                depth: 0,
                articles: root_articles,
            },
        );
    }

    result
}

/// Collect distinct child folder names immediately under `prefix` and
/// emit one flat `FolderGroup` per child, then recurse at depth+1.
fn flatten_subtrees(
    by_path: &std::collections::BTreeMap<String, Vec<ArticleLink>>,
    prefix: &str,
    depth: usize,
) -> Vec<FolderGroup> {
    let mut result = Vec::new();

    // Folders directly under this prefix
    let prefix_slash = if prefix.is_empty() {
        String::new()
    } else {
        format!("{}/", prefix)
    };

    let child_names: Vec<String> = by_path
        .keys()
        .filter_map(|p| {
            if prefix_slash.is_empty() {
                // top-level: matches "xyz" (no slash)
                if !p.contains('/') {
                    Some(p.as_str())
                } else {
                    p.split_once('/').map(|(first, _)| first)
                }
            } else {
                p.strip_prefix(&prefix_slash)
                    .filter(|rest| !rest.is_empty())
                    .map(|rest| rest.split('/').next().unwrap())
            }
        })
        .map(|s| s.to_string())
        .collect::<BTreeSet<_>>()
        .into_iter()
        .collect();

    for name in child_names {
        let child_path = if prefix_slash.is_empty() {
            name.clone()
        } else {
            format!("{}{}", prefix_slash, name)
        };

        let direct = by_path.get(&child_path).cloned().unwrap_or_default();

        result.push(FolderGroup {
            name: name.clone(),
            slug: folder_to_slug(&child_path),
            depth: depth + 1,
            articles: direct,
        });

        result.extend(flatten_subtrees(by_path, &child_path, depth + 1));
    }

    result
}

/// Convert a folder name to a URL-safe slug.
pub fn folder_to_slug(name: &str) -> String {
    name.to_lowercase().replace(' ', "-")
}

/// Convert a URL-safe slug back to the original folder name.
pub fn slug_to_folder(slug: &str, site: &Site) -> Option<String> {
    for (folder_name, _) in site.folder_groups() {
        if folder_to_slug(&folder_name) == slug {
            return Some(folder_name);
        }
    }
    None
}

/// Check if an article is a README file (should be treated as folder description, not an article).
pub(crate) fn is_readme(article: &Article) -> bool {
    let slug = article.slug.to_lowercase();
    slug == "readme" || slug == "reame"
}

/// Build folder metadata for all folders that have published articles.
pub fn build_folder_metas(site: &Site) -> Vec<FolderMetaView> {
    let mut result = Vec::new();
    let published = site.published_articles();

    // Collect all tags per folder (excluding README articles)
    let mut folder_tags: HashMap<String, Vec<String>> = HashMap::new();
    let mut folder_counts: HashMap<String, usize> = HashMap::new();

    let mut all_folder_names: Vec<String> = Vec::new();

    for article in &published {
        if !all_folder_names.contains(&article.folder) {
            all_folder_names.push(article.folder.clone());
        }
        if is_readme(article) {
            continue;
        }
        let count = folder_counts.entry(article.folder.clone()).or_insert(0);
        *count += 1;
        let tags = folder_tags.entry(article.folder.clone()).or_default();
        for tag in &article.tags {
            if !tags.contains(tag) {
                tags.push(tag.clone());
            }
        }
    }

    // Build folder metadata in deterministic order
    all_folder_names.sort();
    // Move empty (root) to front
    if let Some(pos) = all_folder_names.iter().position(|n| n.is_empty()) {
        let root = all_folder_names.remove(pos);
        all_folder_names.insert(0, root);
    }
    let folder_names = all_folder_names;

    for name in &folder_names {
        let slug = folder_to_slug(name);
        let count = folder_counts.get(name).copied().unwrap_or(0);
        let tags = folder_tags.get(name).cloned().unwrap_or_default();

        // Look for a README article in this folder for description
        let readme_html = published
            .iter()
            .find(|a| a.folder == *name && is_readme(a))
            .map(|a| a.content_html.clone());

        // Get article links for this folder (excluding README)
        let article_links: Vec<ArticleLink> = published
            .iter()
            .filter(|a| a.folder == *name && !is_readme(a))
            .map(|a| ArticleLink {
                slug: a.slug.clone(),
                title: a.title.clone(),
            })
            .collect();

        let (display_name, _, image_gradient, icon) =
            folder_display_meta(name, &tags, count);
        let description = readme_html.unwrap_or_default();

        result.push(FolderMetaView {
            slug,
            name: name.clone(),
            display_name,
            description,
            image_gradient,
            icon,
            article_count: count,
            tags,
            articles: article_links,
        });
    }

    result
}

/// Build a directory tree for the given folder, grouping articles by subfolder.
pub fn build_folder_tree(
    root_folder: &str,
    published: &[&Article],
) -> (Vec<ArticleTreeItem>, Vec<TreeLine>) {
    let top_articles: Vec<ArticleTreeItem> = published
        .iter()
        .filter(|a| a.folder == root_folder && !is_readme(a))
        .map(|a| ArticleTreeItem {
            slug: a.slug.clone(),
            title: a.title.clone(),
            date: a.date.clone(),
        })
        .collect();

    let mut tree_lines = Vec::new();
    append_subtree(root_folder, published, 0, &mut tree_lines);

    (top_articles, tree_lines)
}

fn append_subtree(
    parent_folder: &str,
    published: &[&Article],
    depth: usize,
    lines: &mut Vec<TreeLine>,
) {
    let prefix = if parent_folder.is_empty() {
        String::new()
    } else {
        format!("{}/", parent_folder)
    };

    let mut child_map: BTreeMap<String, Vec<&Article>> = BTreeMap::new();
    for article in published {
        if is_readme(article) {
            continue;
        }
        if article.folder == parent_folder {
            continue;
        }
        let rest = if prefix.is_empty() {
            Some(article.folder.as_str())
        } else {
            article.folder.strip_prefix(&prefix)
        };
        if let Some(rest) = rest {
            if rest.is_empty() {
                continue;
            }
            let first = rest.split('/').next().unwrap().to_string();
            child_map.entry(first).or_default().push(article);
        }
    }

    for (name, articles) in &child_map {
        let child_folder = if prefix.is_empty() {
            name.clone()
        } else {
            format!("{}{}", prefix, name)
        };

        // Find README description for this subfolder
        let description = published
            .iter()
            .find(|a| is_readme(a) && a.folder == child_folder)
            .map(|a| a.content_html.clone())
            .unwrap_or_default();

        lines.push(TreeLine {
            padding_left: format!("{}px", depth * 24),
            is_folder: true,
            name: name.clone(),
            slug: folder_to_slug(&child_folder),
            title: String::new(),
            date: String::new(),
            description,
        });

        for article in articles.iter().filter(|a| a.folder == child_folder && !is_readme(a)) {
            lines.push(TreeLine {
                padding_left: format!("{}px", (depth + 1) * 24),
                is_folder: false,
                name: String::new(),
                slug: article.slug.clone(),
                title: article.title.clone(),
                date: article.date.clone(),
                description: String::new(),
            });
        }

        append_subtree(&child_folder, published, depth + 1, lines);
    }
}

/// Auto-generate folder card display metadata from the directory name.
fn folder_display_meta(
    name: &str,
    _tags: &[String],
    _article_count: usize,
) -> (String, String, String, String) {
    let name = if name.is_empty() { "all" } else { name };
    let idx = (name
        .len()
        .wrapping_mul(7)
        .wrapping_add(name.bytes().fold(0u8, |a, b| a.wrapping_add(b)) as usize))
        % 12;
    let gradients = [
        "linear-gradient(135deg, #667eea 0%, #764ba2 100%)",
        "linear-gradient(135deg, #f093fb 0%, #f5576c 100%)",
        "linear-gradient(135deg, #4facfe 0%, #00f2fe 100%)",
        "linear-gradient(135deg, #43e97b 0%, #38f9d7 100%)",
        "linear-gradient(135deg, #fa709a 0%, #fee140 100%)",
        "linear-gradient(135deg, #a18cd1 0%, #fbc2eb 100%)",
        "linear-gradient(135deg, #6366f1 0%, #8b5cf6 100%)",
        "linear-gradient(135deg, #f12711 0%, #f5af19 100%)",
        "linear-gradient(135deg, #0c3483 0%, #a2b6df 100%)",
        "linear-gradient(135deg, #141E30 0%, #243B55 100%)",
        "linear-gradient(135deg, #11998e 0%, #38ef7d 100%)",
        "linear-gradient(135deg, #fc5c7d 0%, #6a82fb 100%)",
    ];
    let icons = [
        "📁", "📂", "📄", "📑", "📊", "📈", "📋", "📌", "📎", "📐", "📚", "📝",
    ];
    let gradient = gradients[idx].to_string();
    let icon = icons[idx].to_string();
    (name.to_string(), String::new(), gradient, icon)
}

async fn index_handler(State(state): State<AppState>) -> Result<Html<String>, AppError> {
    let site = state.site.read().await;

    let tags: Vec<TagView> = site
        .all_tags()
        .into_iter()
        .map(|(name, count)| TagView { name, count })
        .collect();

    let folder_groups = build_folder_groups(&site);
    let folders = build_folder_metas(&site);

    let tpl = IndexTemplate {
        folders,
        tags,
        folder_groups,
    };
    Ok(Html(tpl.render()?))
}

async fn folder_handler(
    State(state): State<AppState>,
    Path(slug): Path<String>,
) -> Result<Html<String>, AppError> {
    let site = state.site.read().await;
    let folder_name = slug_to_folder(&slug, &site).unwrap_or_else(|| slug.replace('-', " "));

    // Build folder meta
    let all_metas = build_folder_metas(&site);
    let folder_meta = all_metas.into_iter().find(|m| m.slug == slug);

    let mut folder_meta = match folder_meta {
        Some(m) => m,
        None => {
            // Create a basic one if not found
            let published: Vec<_> = site.published_articles();
            let prefix = if folder_name.is_empty() {
                String::new()
            } else {
                format!("{}/", folder_name)
            };
            let articles_in_folder: Vec<_> = published
                .iter()
                .filter(|a| a.folder == folder_name || a.folder.starts_with(&prefix))
                .collect();

            if articles_in_folder.is_empty() {
                return Err(AppError::NotFound(slug));
            }

            let (display_name, _, image_gradient, icon) =
                folder_display_meta(&folder_name, &[], articles_in_folder.len());
            let readme_desc = site.published_articles()
                .iter()
                .find(|a| a.folder == folder_name && is_readme(a))
                .map(|a| a.content_html.clone())
                .unwrap_or_default();

            FolderMetaView {
                slug: slug.clone(),
                name: folder_name.clone(),
                display_name,
                description: readme_desc,
                image_gradient,
                icon,
                article_count: articles_in_folder.len(),
                tags: Vec::new(),
                articles: Vec::new(),
            }
        }
    };

    let tags: Vec<TagView> = site
        .all_tags()
        .into_iter()
        .map(|(name, count)| TagView { name, count })
        .collect();

    let folder_groups = build_folder_groups(&site);

    let published_refs: Vec<&Article> = site.published_articles();

    // Count all articles including subfolders
    let prefix = if folder_meta.name.is_empty() {
        String::new()
    } else {
        format!("{}/", folder_meta.name)
    };
    let total_count = published_refs
        .iter()
        .filter(|a| (a.folder == folder_meta.name || a.folder.starts_with(&prefix)) && !is_readme(a))
        .count();
    folder_meta.article_count = total_count;

    let (top_articles, tree_lines) = build_folder_tree(&folder_meta.name, &published_refs);

    let tpl = FolderTreeTemplate {
        folder: folder_meta,
        top_articles,
        tree_lines,
        tags,
        folder_groups,
    };
    Ok(Html(tpl.render()?))
}

async fn article_handler(
    State(state): State<AppState>,
    Path(slug): Path<String>,
) -> Result<Html<String>, AppError> {
    let slug = slug.trim_end_matches(".html").to_string();
    let site = state.site.read().await;
    match site.get_article(&slug) {
        Some(article) => {
            let view = ArticleView {
                slug: article.slug.clone(),
                title: article.title.clone(),
                folder: article.folder.clone(),
                tags: article.tags.clone(),
                date: article.date.clone(),
                content_html: article.content_html.clone(),
            };
            let folder_groups = build_folder_groups(&site);
            let tpl = ArticleTemplate {
                article: view,
                folder_groups,
            };
            Ok(Html(tpl.render()?))
        }
        None => Err(AppError::NotFound(slug)),
    }
}

async fn tag_handler(
    State(state): State<AppState>,
    Path(tag): Path<String>,
) -> Result<Html<String>, AppError> {
    let site = state.site.read().await;
    let articles: Vec<ArticleView> = site
        .get_articles_by_tag(&tag)
        .into_iter()
        .map(|a| ArticleView {
            slug: a.slug.clone(),
            title: a.title.clone(),
            folder: a.folder.clone(),
            tags: a.tags.clone(),
            date: a.date.clone(),
            content_html: truncate_html(&a.content_html, 300),
        })
        .collect();

    let folder_groups = build_folder_groups(&site);
    let tpl = TagTemplate {
        tag,
        articles,
        folder_groups,
    };
    Ok(Html(tpl.render()?))
}

async fn search_index_handler(State(state): State<AppState>) -> Json<Vec<SearchIndexEntry>> {
    let site = state.site.read().await;
    let entries: Vec<SearchIndexEntry> = site
        .published_articles()
        .into_iter()
        .filter(|a| !is_readme(a))
        .map(|a| {
            let plain = strip_html(&a.content_html);
            let excerpt: String = plain.chars().take(500).collect();
            SearchIndexEntry {
                slug: a.slug.clone(),
                title: a.title.clone(),
                tags: a.tags.clone(),
                excerpt,
            }
        })
        .collect();
    Json(entries)
}

/// Strip HTML tags for plain-text excerpt.
pub(crate) fn strip_html(html: &str) -> String {
    let mut out = String::new();
    let mut in_tag = false;
    for ch in html.chars() {
        match ch {
            '<' => in_tag = true,
            '>' => in_tag = false,
            _ if !in_tag => out.push(ch),
            _ => {}
        }
    }
    // Collapse whitespace
    let re = out.split_whitespace().collect::<Vec<_>>();
    re.join(" ")
}

/// Truncate HTML to approximately `max_chars` visible characters.
pub(crate) fn truncate_html(html: &str, max_chars: usize) -> String {
    if html.len() <= max_chars {
        return html.to_string();
    }

    let mut out = String::new();
    let mut chars = 0;
    let mut in_tag = false;

    for ch in html.chars() {
        if ch == '<' {
            in_tag = true;
        }
        if !in_tag {
            if !ch.is_whitespace() {
                chars += 1;
            }
        }
        out.push(ch);
        if ch == '>' {
            in_tag = false;
        }
        if chars >= max_chars && !in_tag {
            out.push_str("…");
            break;
        }
    }

    out
}

/// Application error types
enum AppError {
    NotFound(String),
    Render(askama::Error),
}

impl From<askama::Error> for AppError {
    fn from(e: askama::Error) -> Self {
        AppError::Render(e)
    }
}

impl IntoResponse for AppError {
    fn into_response(self) -> Response {
        match self {
            AppError::NotFound(slug) => {
                Html(format!(
                    r#"<!DOCTYPE html><html><head><meta charset="utf-8"><title>404 - Not Found</title><link rel="stylesheet" href="/css/style.css"></head><body><main><h1>404</h1><p>Article "{}" not found.</p><a href="/">← Back to home</a></main></body></html>"#,
                    slug
                ))
                .into_response()
            }
            AppError::Render(e) => {
                tracing::error!("Template render error: {}", e);
                Html(
                    r#"<!DOCTYPE html><html><head><meta charset="utf-8"><title>500</title><link rel="stylesheet" href="/css/style.css"></head><body><main><h1>500</h1><p>Internal server error</p></main></body></html>"#
                        .to_string(),
                )
                .into_response()
            }
        }
    }
}

#[cfg(test)]
mod tests {
    use super::*;
    use crate::article::Article;
    use crate::content::Site;

    fn make_article(slug: &str, folder: &str, title: &str, content: &str) -> Article {
        Article {
            slug: slug.to_string(),
            title: title.to_string(),
            folder: folder.to_string(),
            tags: vec![],
            draft: false,
            date: String::new(),
            content_html: content.to_string(),
        }
    }

    #[test]
    fn test_is_readme() {
        assert!(is_readme(&make_article("README", "rust", "Readme", "<p>desc</p>")));
        assert!(is_readme(&make_article("readme", "", "Readme", "<p>desc</p>")));
        assert!(is_readme(&make_article("reame", "", "Reame", "<p>typo</p>")));
        assert!(is_readme(&make_article("REAME", "rust", "Reame", "<p>typo</p>")));
        assert!(!is_readme(&make_article("guide", "rust", "Guide", "<p>body</p>")));
        assert!(!is_readme(&make_article("readme-guide", "", "Guide", "<p>body</p>")));
    }

    #[test]
    fn test_build_folder_metas_excludes_readme() {
        let articles = vec![
            make_article("README", "rust", "Readme", "<p>README content</p>"),
            make_article("guide", "rust", "Rust Guide", "<p>body</p>"),
            make_article("intro", "", "Intro", "<p>root</p>"),
        ];
        let site = Site::_new_for_test(articles);
        let metas = build_folder_metas(&site);

        let rust_meta = metas.iter().find(|m| m.slug == "rust").unwrap();
        assert_eq!(rust_meta.article_count, 1, "README excluded from count");
        assert_eq!(rust_meta.description, "<p>README content</p>", "README HTML becomes description");
        assert_eq!(rust_meta.articles.len(), 1, "only non-README in links");
        assert_eq!(rust_meta.articles[0].title, "Rust Guide");
    }

    #[test]
    fn test_build_folder_tree_excludes_readme() {
        let articles = vec![
            make_article("README", "rust", "Readme", "<p>desc</p>"),
            make_article("guide", "rust", "Rust Guide", "<p>body</p>"),
            make_article("nested", "rust/advanced", "Advanced", "<p>nested</p>"),
        ];
        let site = Site::_new_for_test(articles);
        let published: Vec<&Article> = site.published_articles();

        let (top_articles, tree_lines) = build_folder_tree("rust", &published);
        assert_eq!(top_articles.len(), 1, "README not in top_articles");
        assert_eq!(top_articles[0].title, "Rust Guide");
        let readme_in_tree = tree_lines.iter().any(|l| l.slug == "readme");
        assert!(!readme_in_tree, "README not in tree_lines");
    }

    #[test]
    fn test_folder_without_readme_has_empty_description() {
        let articles = vec![
            make_article("guide", "rust", "Rust Guide", "<p>body</p>"),
        ];
        let site = Site::_new_for_test(articles);
        let metas = build_folder_metas(&site);
        let rust_meta = metas.iter().find(|m| m.slug == "rust").unwrap();
        assert_eq!(rust_meta.description, "");
        assert_eq!(rust_meta.article_count, 1);
    }

    #[test]
    fn test_readme_only_folder_shows_zero_articles() {
        let articles = vec![
            make_article("README", "rust", "Readme", "<p>desc</p>"),
        ];
        let site = Site::_new_for_test(articles);
        let metas = build_folder_metas(&site);
        let rust_meta = metas.iter().find(|m| m.slug == "rust").unwrap();
        assert_eq!(rust_meta.article_count, 0, "README-only folder has zero articles");
        assert_eq!(rust_meta.description, "<p>desc</p>");
        assert!(rust_meta.articles.is_empty());
    }
}

use crate::article::{Article, parse_article};
use anyhow::Result;
use notify::{Event, EventKind, RecursiveMode, Watcher};
use std::collections::{BTreeMap, BTreeSet, HashMap};
use std::path::{Path, PathBuf};
use std::sync::Arc;
use tokio::sync::RwLock;
use tracing::info;

/// The site holds all loaded articles in memory.
pub struct Site {
    articles: Vec<Article>,
    slug_index: HashMap<String, usize>,
    tag_index: HashMap<String, Vec<usize>>,
    /// Articles grouped by folder: (folder_name, [article_index, ...])
    folder_groups: Vec<(String, Vec<usize>)>,
}

impl Site {
    fn new(articles: Vec<Article>) -> Self {
        Self::_new_for_test(articles)
    }

    /// Public constructor for testing only.
    #[doc(hidden)]
    pub fn _new_for_test(articles: Vec<Article>) -> Self {
        let mut slug_index = HashMap::new();
        let mut tag_index: HashMap<String, Vec<usize>> = HashMap::new();
        // BTreeMap for deterministic folder ordering
        let mut folders: BTreeMap<String, Vec<usize>> = BTreeMap::new();

        for (i, article) in articles.iter().enumerate() {
            slug_index.insert(article.slug.clone(), i);
            for tag in &article.tags {
                tag_index.entry(tag.clone()).or_default().push(i);
            }
            folders.entry(article.folder.clone()).or_default().push(i);
        }

        // Build ordered folder groups: root (empty) first, then alphabetically
        let mut folder_groups = Vec::with_capacity(folders.len());
        if let Some(root) = folders.remove("") {
            folder_groups.push((String::new(), root));
        }
        for (name, indices) in folders {
            folder_groups.push((name, indices));
        }

        Self {
            articles,
            slug_index,
            tag_index,
            folder_groups,
        }
    }

    pub fn published_articles(&self) -> Vec<&Article> {
        self.articles.iter().filter(|a| !a.draft).collect()
    }

    pub fn get_article(&self, slug: &str) -> Option<&Article> {
        self.slug_index.get(slug).map(|&i| &self.articles[i])
    }

    pub fn get_articles_by_tag(&self, tag: &str) -> Vec<&Article> {
        self.tag_index
            .get(tag)
            .map(|indices| {
                indices
                    .iter()
                    .filter_map(|&i| {
                        let a = &self.articles[i];
                        if !a.draft { Some(a) } else { None }
                    })
                    .collect()
            })
            .unwrap_or_default()
    }

    pub fn all_tags(&self) -> BTreeSet<(String, usize)> {
        let mut tag_counts: HashMap<String, usize> = HashMap::new();
        for article in &self.articles {
            if article.draft {
                continue;
            }
            for tag in &article.tags {
                *tag_counts.entry(tag.clone()).or_default() += 1;
            }
        }
        let mut result: BTreeSet<(String, usize)> = BTreeSet::new();
        for (tag, count) in tag_counts {
            result.insert((tag, count));
        }
        result
    }

    /// Returns folder groups with published articles.
    /// Each group is (folder_name, Vec<&Article>). Root (empty) comes first.
    pub fn folder_groups(&self) -> Vec<(String, Vec<&Article>)> {
        self.folder_groups
            .iter()
            .map(|(name, indices)| {
                let articles: Vec<&Article> = indices
                    .iter()
                    .filter_map(|&i| {
                        let a = &self.articles[i];
                        if !a.draft { Some(a) } else { None }
                    })
                    .collect();
                (name.clone(), articles)
            })
            .filter(|(_, articles)| !articles.is_empty())
            .collect()
    }
}

/// Load all markdown content from the given directory.
pub fn load_content(content_dir: &Path) -> Result<Site> {
    let mut articles = Vec::new();

    if !content_dir.exists() {
        info!(
            "Content directory {:?} does not exist, creating it",
            content_dir
        );
        std::fs::create_dir_all(content_dir)?;
        return Ok(Site::new(articles));
    }

    let mut entries: Vec<PathBuf> = Vec::new();
    collect_md_files(content_dir, &mut entries)?;
    entries.sort();

    for path in &entries {
        let raw = std::fs::read_to_string(path)?;
        match parse_article(path, content_dir, &raw) {
            Ok(article) => {
                info!("Loaded article: {}", article.title);
                articles.push(article);
            }
            Err(e) => {
                tracing::warn!("Failed to parse {:?}: {}", path, e);
            }
        }
    }

    Ok(Site::new(articles))
}

fn collect_md_files(dir: &Path, out: &mut Vec<PathBuf>) -> Result<()> {
    for entry in std::fs::read_dir(dir)? {
        let entry = entry?;
        let path = entry.path();
        if path.is_dir() {
            collect_md_files(&path, out)?;
        } else if path.extension().and_then(|s| s.to_str()) == Some("md") {
            out.push(path);
        }
    }
    Ok(())
}

/// Start a file watcher that reloads content on change.
pub fn start_file_watcher(content_dir: PathBuf, site: Arc<RwLock<Site>>) -> Result<impl Watcher> {
    let watch_dir = content_dir.clone();
    let mut watcher = notify::recommended_watcher(move |res: Result<Event, notify::Error>| {
        if let Ok(event) = res {
            if matches!(
                event.kind,
                EventKind::Create(_) | EventKind::Modify(_) | EventKind::Remove(_)
            ) {
                info!("Content directory changed, reloading...");
                if let Ok(new_site) = load_content(&watch_dir) {
                    let mut site = site.blocking_write();
                    *site = new_site;
                    info!("Content reloaded");
                }
            }
        }
    })?;

    watcher.watch(&content_dir, RecursiveMode::Recursive)?;
    Ok(watcher)
}

use pulldown_cmark::{CodeBlockKind, Event, HeadingLevel, Options, Parser, Tag, TagEnd};
use std::collections::HashMap;
use std::sync::OnceLock;
use syntect::easy::HighlightLines;
use syntect::highlighting::ThemeSet;
use syntect::html::{IncludeBackground, styled_line_to_highlighted_html};
use syntect::parsing::SyntaxSet;
use syntect::util::LinesWithEndings;

/// Renders markdown to HTML with side-notes for footnote definitions
pub fn render_markdown<'a>(md: &'a str) -> String {
    let mut options = Options::empty();
    options.insert(Options::ENABLE_FOOTNOTES);
    options.insert(Options::ENABLE_TABLES);
    options.insert(Options::ENABLE_STRIKETHROUGH);
    options.insert(Options::ENABLE_TASKLISTS);
    options.insert(Options::ENABLE_HEADING_ATTRIBUTES);
    options.insert(Options::ENABLE_MATH);

    let parser = Parser::new_ext(md, options);
    let events: Vec<Event<'a>> = parser.collect();

    // Separate footnote definitions from main content
    let mut footnote_defs: HashMap<String, Vec<Event<'a>>> = HashMap::new();
    let mut content_events: Vec<Event<'a>> = Vec::new();
    let mut in_fn = false;
    let mut fn_name = String::new();
    let mut fn_events: Vec<Event<'a>> = Vec::new();

    for event in events {
        match &event {
            Event::Start(Tag::FootnoteDefinition(name)) => {
                in_fn = true;
                fn_name = name.to_string();
                fn_events.clear();
            }
            Event::End(TagEnd::FootnoteDefinition) => {
                in_fn = false;
                footnote_defs.insert(fn_name.clone(), fn_events.clone());
            }
            _ => {
                if in_fn {
                    fn_events.push(event);
                } else {
                    content_events.push(event);
                }
            }
        }
    }

    // Render content events into HTML
    let mut html = String::new();
    let mut active_footnotes: Vec<String> = Vec::new();
    let mut in_code_block = false;
    let mut code_lang = String::new();
    let mut code_content = String::new();
    let mut in_img = false;
    let mut img_url = String::new();
    let mut img_title = String::new();
    let mut img_alt = String::new();

    for event in content_events {
        match event {
            Event::Start(tag) => match tag {
                Tag::Paragraph => {
                    active_footnotes.clear();
                    html.push_str("<p>");
                }
                Tag::Heading { level, .. } => {
                    let h = heading_level_to_u32(level);
                    html.push_str(&format!("<h{}>", h));
                }
                Tag::BlockQuote(kind) => {
                    html.push_str("<blockquote>");
                    let _ = kind;
                }
                Tag::CodeBlock(kind) => {
                    code_lang = match kind {
                        CodeBlockKind::Fenced(info_string) => info_string
                            .split_whitespace()
                            .next()
                            .unwrap_or("")
                            .to_string(),
                        CodeBlockKind::Indented => String::new(),
                    };
                    in_code_block = true;
                    code_content.clear();
                }
                Tag::List(start) => {
                    if start.is_some() {
                        html.push_str("<ol>");
                    } else {
                        html.push_str("<ul>");
                    }
                }
                Tag::Item => {
                    html.push_str("<li>");
                }
                Tag::Table(_alignments) => {
                    html.push_str("<table>");
                }
                Tag::TableHead => {
                    html.push_str("<thead>");
                }
                Tag::TableRow => {
                    html.push_str("<tr>");
                }
                Tag::TableCell => {
                    html.push_str("<td>");
                }
                Tag::Emphasis => {
                    html.push_str("<em>");
                }
                Tag::Strong => {
                    html.push_str("<strong>");
                }
                Tag::Strikethrough => {
                    html.push_str("<del>");
                }
                Tag::Link {
                    dest_url, title, ..
                } => {
                    let title_attr = if title.is_empty() {
                        String::new()
                    } else {
                        format!(" title=\"{}\"", escape_attr(&title))
                    };
                    html.push_str(&format!(
                        "<a href=\"{}\"{}>",
                        escape_attr(&dest_url),
                        title_attr
                    ));
                }
                Tag::Image {
                    dest_url, title, ..
                } => {
                    in_img = true;
                    img_url = dest_url.to_string();
                    img_title = title.to_string();
                    img_alt.clear();
                }
                Tag::DefinitionList => {
                    html.push_str("<dl>");
                }
                Tag::DefinitionListTitle => {
                    html.push_str("<dt>");
                }
                Tag::DefinitionListDefinition => {
                    html.push_str("<dd>");
                }
                Tag::MetadataBlock(_) => {}
                _ => {}
            },
            Event::End(tag_end) => {
                let mut block_end = false;
                match &tag_end {
                    TagEnd::Paragraph => {
                        block_end = true;
                        html.push_str("</p>");
                    }
                    TagEnd::Heading(level) => {
                        block_end = true;
                        let h = heading_level_to_u32(*level);
                        html.push_str(&format!("</h{}>", h));
                    }
                    TagEnd::BlockQuote(_kind) => {
                        block_end = true;
                        html.push_str("</blockquote>");
                    }
                    TagEnd::CodeBlock => {
                        in_code_block = false;
                        if code_lang == "mermaid" {
                            html.push_str("<pre class=\"mermaid\">");
                            html.push_str(&code_content);
                            html.push_str("</pre>");
                        } else if !code_lang.is_empty() {
                            let dark =
                                highlight_code(&code_content, &code_lang, "base16-ocean.dark");
                            let light = highlight_code(&code_content, &code_lang, "InspiredGitHub");
                            html.push_str(&format!(
                                "<pre class=\"code-block-dark\"><code class=\"language-{}\">",
                                code_lang
                            ));
                            html.push_str(&dark);
                            html.push_str("</code></pre>");
                            html.push_str(&format!(
                                "<pre class=\"code-block-light\"><code class=\"language-{}\">",
                                code_lang
                            ));
                            html.push_str(&light);
                            html.push_str("</code></pre>");
                        } else {
                            html.push_str("<pre><code>");
                            html.push_str(&escape_html(&code_content));
                            html.push_str("</code></pre>");
                        }
                    }
                    TagEnd::List(false) => {
                        html.push_str("</ul>");
                    }
                    TagEnd::List(true) => {
                        html.push_str("</ol>");
                    }
                    TagEnd::Item => {
                        block_end = true;
                        html.push_str("</li>");
                    }
                    TagEnd::Table => {
                        block_end = true;
                        html.push_str("</table>");
                    }
                    TagEnd::TableHead => {
                        html.push_str("</thead>");
                    }
                    TagEnd::TableRow => {
                        html.push_str("</tr>");
                    }
                    TagEnd::TableCell => {
                        block_end = true;
                        html.push_str("</td>");
                    }
                    TagEnd::Emphasis => {
                        html.push_str("</em>");
                    }
                    TagEnd::Strong => {
                        html.push_str("</strong>");
                    }
                    TagEnd::Strikethrough => {
                        html.push_str("</del>");
                    }
                    TagEnd::Link => {
                        html.push_str("</a>");
                    }
                    TagEnd::Image => {
                        in_img = false;
                        let title_attr = if img_title.is_empty() {
                            String::new()
                        } else {
                            format!(" title=\"{}\"", escape_attr(&img_title))
                        };
                        html.push_str(&format!(
                            "<img src=\"{}\"{} alt=\"{}\" />",
                            escape_attr(&img_url),
                            title_attr,
                            escape_attr(&img_alt)
                        ));
                    }
                    TagEnd::DefinitionList => {
                        block_end = true;
                        html.push_str("</dl>");
                    }
                    TagEnd::DefinitionListTitle => {
                        html.push_str("</dt>");
                    }
                    TagEnd::DefinitionListDefinition => {
                        block_end = true;
                        html.push_str("</dd>");
                    }
                    TagEnd::MetadataBlock(_) => {}
                    _ => {}
                }
                if block_end {
                    for name in &active_footnotes {
                        if let Some(events) = footnote_defs.get(name) {
                            html.push_str(&format!(
                                "<aside class=\"footnote-side\" id=\"fn-{}\">",
                                name
                            ));
                            html.push_str("<sup class=\"fn-marker\">");
                            html.push_str(name);
                            html.push_str("</sup> ");
                            html.push_str(&render_footnote_events(events));
                            html.push_str("</aside>");
                        }
                    }
                    active_footnotes.clear();
                }
            }
            Event::Text(text) => {
                if in_code_block {
                    code_content.push_str(&text);
                } else if in_img {
                    img_alt.push_str(&text);
                } else {
                    html.push_str(&escape_html(&text));
                }
            }
            Event::Code(text) => {
                html.push_str(&format!("<code>{}</code>", escape_html(&text)));
            }
            Event::Html(html_raw) => {
                if in_code_block {
                    code_content.push_str(&html_raw);
                } else {
                    html.push_str(&html_raw);
                }
            }
            Event::SoftBreak => {
                if in_code_block {
                    code_content.push('\n');
                } else {
                    html.push(' ');
                }
            }
            Event::HardBreak => {
                html.push_str("<br />\n");
            }
            Event::Rule => {
                html.push_str("<hr />\n");
            }
            Event::TaskListMarker(checked) => {
                if checked {
                    html.push_str("<input type=\"checkbox\" checked disabled />");
                } else {
                    html.push_str("<input type=\"checkbox\" disabled />");
                }
            }
            Event::InlineHtml(html_raw) => {
                html.push_str(&html_raw);
            }
            Event::InlineMath(math) => {
                html.push_str(&format!("\\({}\\)", math));
            }
            Event::DisplayMath(math) => {
                html.push_str(&format!("\\[{}\\]", math));
            }
            Event::FootnoteReference(name) => {
                html.push_str(&format!(
                    "<sup class=\"footnote-ref\" id=\"fnref-{}\"><a href=\"#fn-{}\">[{}]</a></sup>",
                    name, name, name
                ));
                active_footnotes.push(name.to_string());
            }
        }
    }

    html
}

fn heading_level_to_u32(level: HeadingLevel) -> u32 {
    match level {
        HeadingLevel::H1 => 1,
        HeadingLevel::H2 => 2,
        HeadingLevel::H3 => 3,
        HeadingLevel::H4 => 4,
        HeadingLevel::H5 => 5,
        HeadingLevel::H6 => 6,
    }
}

/// Render footnote content events to HTML string
fn render_footnote_events(events: &[Event]) -> String {
    let mut html = String::new();

    for event in events {
        match event {
            Event::Start(tag) => match tag {
                Tag::Paragraph => html.push_str("<span class=\"fn-text\">"),
                Tag::Emphasis => html.push_str("<em>"),
                Tag::Strong => html.push_str("<strong>"),
                Tag::Strikethrough => html.push_str("<del>"),
                Tag::CodeBlock(_) => html.push_str("<code>"),
                Tag::Link {
                    dest_url, title, ..
                } => {
                    let title_attr = if title.is_empty() {
                        String::new()
                    } else {
                        format!(" title=\"{}\"", escape_attr(title))
                    };
                    html.push_str(&format!(
                        "<a href=\"{}\"{}>",
                        escape_attr(dest_url),
                        title_attr
                    ));
                }
                Tag::List(_) => html.push_str("<ul>"),
                Tag::Item => html.push_str("<li>"),
                _ => {}
            },
            Event::End(tag_end) => match tag_end {
                TagEnd::Paragraph => html.push_str("</span>"),
                TagEnd::Emphasis => html.push_str("</em>"),
                TagEnd::Strong => html.push_str("</strong>"),
                TagEnd::Strikethrough => html.push_str("</del>"),
                TagEnd::CodeBlock => html.push_str("</code>"),
                TagEnd::Link => html.push_str("</a>"),
                TagEnd::List(_) => html.push_str("</ul>"),
                TagEnd::Item => html.push_str("</li>"),
                _ => {}
            },
            Event::Text(text) => html.push_str(&escape_html(text)),
            Event::Code(text) => html.push_str(&format!("<code>{}</code>", escape_html(text))),
            Event::SoftBreak => html.push(' '),
            Event::HardBreak => html.push_str("<br />"),
            Event::Html(html_raw) => html.push_str(html_raw),
            _ => {}
        }
    }

    html
}

fn highlight_code(code: &str, lang: &str, theme_name: &str) -> String {
    let ss = get_syntax_set();
    let Some(syntax) = ss.find_syntax_by_token(lang) else {
        return escape_html(code);
    };
    let ts = get_theme_set();
    let theme = &ts.themes[theme_name];

    let mut highlighter = HighlightLines::new(syntax, theme);
    let mut result = String::new();
    for line in LinesWithEndings::from(code) {
        if let Ok(ranges) = highlighter.highlight_line(line, ss) {
            if let Ok(html) = styled_line_to_highlighted_html(&ranges, IncludeBackground::No) {
                result.push_str(&html);
            }
        }
    }
    result
}

fn get_syntax_set() -> &'static SyntaxSet {
    static SS: OnceLock<SyntaxSet> = OnceLock::new();
    SS.get_or_init(|| SyntaxSet::load_defaults_newlines())
}

fn get_theme_set() -> &'static ThemeSet {
    static TS: OnceLock<ThemeSet> = OnceLock::new();
    TS.get_or_init(|| ThemeSet::load_defaults())
}

fn escape_html(s: &str) -> String {
    s.replace('&', "&amp;")
        .replace('<', "&lt;")
        .replace('>', "&gt;")
        .replace('"', "&quot;")
}

fn escape_attr(s: &str) -> String {
    s.replace('&', "&amp;")
        .replace('"', "&quot;")
        .replace('<', "&lt;")
        .replace('>', "&gt;")
}

