use crate::renderer::render_markdown;
use serde::Deserialize;
use std::path::Path;

#[derive(Debug, Clone, Deserialize)]
pub struct Frontmatter {
    pub title: Option<String>,
    #[serde(default)]
    pub tags: Option<Vec<String>>,
    pub draft: Option<bool>,
    pub date: Option<String>,
}

#[derive(Debug, Clone)]
pub struct Article {
    pub slug: String,
    pub title: String,
    pub folder: String,
    pub tags: Vec<String>,
    pub draft: bool,
    pub date: String,
    pub content_html: String,
}

/// Parse the raw markdown (which includes frontmatter) into an Article.
/// `content_dir` is the root content directory, used to compute the folder.
pub fn parse_article(path: &Path, content_dir: &Path, raw: &str) -> anyhow::Result<Article> {
    let slug = path
        .file_stem()
        .and_then(|s| s.to_str())
        .unwrap_or("untitled")
        .to_string();

    let folder = compute_folder(path, content_dir);

    let (frontmatter, body) = split_frontmatter(raw);

    let fm: Frontmatter = if let Some(yaml) = frontmatter {
        serde_yaml::from_str(yaml)?
    } else {
        Frontmatter {
            title: None,
            tags: None,
            draft: None,
            date: None,
        }
    };

    let title = fm.title.clone().unwrap_or_else(|| slug.clone());
    let tags = fm.tags.clone().unwrap_or_default();
    let draft = fm.draft.unwrap_or(false);
    let date = fm.date.clone().unwrap_or_default();

    let content_html = render_markdown(body);

    Ok(Article {
        slug,
        title,
        folder,
        tags,
        draft,
        date,
        content_html,
    })
}

/// Compute the folder path for an article relative to content_dir.
/// Articles directly in content_dir get an empty folder string.
/// `content/foo.md` → `""`
/// `content/rust/foo.md` → `"rust"`
/// `content/rust/tutorials/foo.md` → `"rust/tutorials"`
fn compute_folder(path: &Path, content_dir: &Path) -> String {
    let parent = path.parent().unwrap_or(Path::new(""));
    if parent == content_dir {
        return String::new();
    }
    let relative = parent.strip_prefix(content_dir).unwrap_or(parent);
    relative
        .components()
        .map(|c| c.as_os_str().to_string_lossy())
        .collect::<Vec<_>>()
        .join("/")
}

/// Split raw markdown into optional frontmatter (YAML) and body.
/// Expects frontmatter delimited by `---\n` at the very start.
fn split_frontmatter(raw: &str) -> (Option<&str>, &str) {
    let raw = raw.trim_start();
    if let Some(rest) = raw.strip_prefix("---\n") {
        if let Some(end) = rest.find("\n---\n") {
            let yaml = &rest[..end];
            let body = &rest[end + 5..];
            return (Some(yaml), body);
        }
        if let Some(end) = rest.find("\n---") {
            let yaml = &rest[..end];
            let body = &rest[end + 5..];
            return (Some(yaml), body);
        }
    }
    (None, raw)
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_split_frontmatter() {
        let input = "---\ntitle: Hello\n---\n\nBody text";
        let (fm, body) = split_frontmatter(input);
        assert_eq!(fm, Some("title: Hello"));
        assert_eq!(body, "\n\nBody text");
    }

    #[test]
    fn test_frontmatter_with_tags() {
        let input = "---\ntitle: Test\ntags: [a, b]\ndraft: false\n---\n\nContent";
        let (fm, _body) = split_frontmatter(input);
        let parsed: Frontmatter = serde_yaml::from_str(fm.unwrap()).unwrap();
        assert_eq!(parsed.title.unwrap(), "Test");
        assert_eq!(parsed.tags.unwrap(), vec!["a", "b"]);
        assert!(!parsed.draft.unwrap());
    }

    #[test]
    fn test_no_frontmatter() {
        let input = "Just a body\nwith text";
        let (fm, body) = split_frontmatter(input);
        assert!(fm.is_none());
        assert_eq!(body, "Just a body\nwith text");
    }

    #[test]
    fn test_compute_folder_root() {
        let content = Path::new("/content");
        let file = Path::new("/content/foo.md");
        assert_eq!(compute_folder(file, &content), "");
    }

    #[test]
    fn test_compute_folder_subdir() {
        let content = Path::new("/content");
        let file = Path::new("/content/rust/foo.md");
        assert_eq!(compute_folder(file, &content), "rust");
    }

    #[test]
    fn test_compute_folder_nested() {
        let content = Path::new("/content");
        let file = Path::new("/content/rust/tutorials/foo.md");
        assert_eq!(compute_folder(file, &content), "rust/tutorials");
    }

    #[test]
    fn test_slug_from_filename() {
        let path = Path::new("hello-world.md");
        let slug = path.file_stem().unwrap().to_str().unwrap();
        assert_eq!(slug, "hello-world");
    }
}

