{% extends "base.html" %} {% block title %}{{ folder.display_name }} — Mizushi{% endblock %} {% block content %}
<div class="folder-page-wrapper">
    <section class="folder-hero-section">
        <a href="/" class="back-link">&larr; すべてのカテゴリ</a>
        <div class="folder-hero">
            <div
                class="folder-hero-icon"
                style="background: {{ folder.image_gradient }}"
            >
                <span>{{ folder.icon }}</span>
            </div>
            <div class="folder-hero-text">
                <h1 class="folder-hero-title">{{ folder.display_name }}</h1>
                {% if !folder.description.is_empty() %}
                <p class="folder-hero-description">{{ folder.description|safe }}</p>
                {% endif %}
                <div class="folder-hero-meta">
                    <span class="folder-hero-count"
                        >{{ folder.article_count }} articles</span
                    >
                </div>
            </div>
        </div>
    </section>

    <section class="tree-listing-section">
        {% if top_articles.is_empty() && tree_lines.is_empty() %}
        <p class="empty-state">このカテゴリにはまだ記事がありません。</p>
        {% else %}
        <div class="tree-listing">
            {% for article in top_articles %}
            <div class="tree-item tree-article" style="padding-left: 0">
                <span class="tree-bullet">・</span>
                <a href="/article/{{ article.slug }}" class="tree-link">{{ article.title }}</a>
                {% if !article.date.is_empty() %}
                <span class="tree-date">{{ article.date }}</span>
                {% endif %}
            </div>
            {% endfor %}

            {% for line in tree_lines %}
                {% if line.is_folder %}
                <div class="tree-item tree-folder" style="padding-left: {{ line.padding_left }}">
                    <a href="/folder/{{ line.slug }}">{{ line.name }}</a>
                    {% if !line.description.is_empty() %}
                    <div class="tree-folder-description">{{ line.description|safe }}</div>
                    {% endif %}
                </div>
                {% else %}
                <div class="tree-item tree-article" style="padding-left: {{ line.padding_left }}">
                    <span class="tree-bullet">・</span>
                    <a href="/article/{{ line.slug }}" class="tree-link">{{ line.title }}</a>
                    {% if !line.date.is_empty() %}
                    <span class="tree-date">{{ line.date }}</span>
                    {% endif %}
                </div>
                {% endif %}
            {% endfor %}
        </div>
        {% endif %}
    </section>
</div>
{% endblock %}

